mapper.select:
SELECT COMMON_ID , TYPE_CD , GETMULTINAME_COMMONID(GATE_CD, #{ses.langCd}, COMMON_ID, 'TT') AS TITLE_TEXT , GETMULTINAME_COMMONID(GATE_CD, #{ses.langCd}, COMMON_ID, 'LT') AS LIST_ITEM_TEXT , GETMULTINAME_COMMONID(GATE_CD, #{ses.langCd}, COMMON_ID, 'CC') AS COMMON_DESC , LIST_ITEM_CD , SQL_TEXT , DATABASE_CD FROM STOCCMPC WHERE GATE_CD = #{ses.gateCd} AND DEL_FLAG = '0'
AND USE_FLAG = #{USE_FLAG}
AND TYPE_CD = #{TYPE}
AND DATABASE_CD = #{DATABASE}
AND UPPER(COMMON_ID) LIKE '%' UPPER(#{COMMON_ID}) '%'
AND ( UPPER(GETMULTINAME_COMMONID(GATE_CD, #{ses.langCd}, COMMON_ID, 'CC')) LIKE '%' UPPER(#{COMMON_DESC}) '%' OR UPPER(getMultiNameByCommonId(GATE_CD, #{ses.langCd}, COMMON_ID, 'TT')) LIKE '%' UPPER(#{COMMON_DESC}) '%')
AND UPPER(SQL_TEXT) LIKE '%' UPPER(#{SQL_TEXT}) '%'
ORDER BY COMMON_ID, DATABASE_CD
